import React, { useState, useEffect } from 'react';
import axios from 'axios';

export default function Marketplace() {
  const [loads, setLoads] = useState([]);
  const [form, setForm] = useState({ origin: '', destination: '', weight: '', price: '' });

  const fetchData = async () => {
    const res = await axios.get("http://localhost:5000/api/loads/all");
    setLoads(res.data);
  };

  useEffect(() => { fetchData(); }, []);

  const handlePost = async (e) => {
    e.preventDefault();
    await axios.post("http://localhost:5000/api/loads/add", form);
    setForm({ origin: '', destination: '', weight: '', price: '' });
    fetchData();
  };

  const handleBook = async (id) => {
    await axios.patch(`http://localhost:5000/api/loads/book/${id}`);
    alert("🚛 Load Booked Successfully!");
    fetchData();
  };

  return (
    <div className="min-h-screen bg-yellow-50 font-sans">
      {/* Red Navbar */}
      <nav className="bg-red-600 p-4 text-white flex justify-between items-center shadow-lg">
        <h1 className="text-2xl font-black italic">TRUCK LOAD BOARD</h1>
        <button onClick={() => window.location.href='/login'} className="bg-black px-4 py-2 rounded-lg text-xs font-bold uppercase">Logout</button>
      </nav>

      <div className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-12 gap-8">
        {/* Left Side: Form */}
        <div className="lg:col-span-4">
          <form onSubmit={handlePost} className="bg-white p-8 rounded-3xl shadow-xl border-t-8 border-red-600 sticky top-6">
            <h2 className="text-xl font-black mb-6 uppercase text-red-600 italic italic">Post Freight</h2>
            <div className="space-y-4">
              <input type="text" placeholder="Origin" className="w-full p-4 bg-gray-50 rounded-xl font-bold" value={form.origin} onChange={e => setForm({...form, origin: e.target.value})} required />
              <input type="text" placeholder="Destination" className="w-full p-4 bg-gray-50 rounded-xl font-bold" value={form.destination} onChange={e => setForm({...form, destination: e.target.value})} required />
              <input type="number" placeholder="Price ($)" className="w-full p-4 bg-gray-50 rounded-xl font-bold" value={form.price} onChange={e => setForm({...form, price: e.target.value})} required />
              <button className="w-full bg-red-600 text-white py-4 rounded-xl font-black uppercase hover:bg-red-700 transition shadow-lg">Post Load</button>
            </div>
          </form>
        </div>

        {/* Right Side: Live Loads */}
        <div className="lg:col-span-8">
          <h2 className="text-3xl font-black mb-6 italic uppercase underline decoration-red-600">Live Loads ●</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {loads.map(l => (
              <div key={l._id} className={`p-6 rounded-3xl shadow-xl border-b-8 border-black transition-all ${l.isBooked ? 'bg-gray-100 opacity-60' : 'bg-white hover:-translate-y-2'}`}>
                <div className="flex justify-between items-start mb-4">
                  <span className={`text-[10px] font-black px-2 py-1 rounded uppercase ${l.isBooked ? 'bg-gray-300' : 'bg-yellow-400'}`}>
                    {l.isBooked ? 'Booked' : 'Available'}
                  </span>
                  <span className="text-2xl font-black text-green-600">${l.price}</span>
                </div>
                <h3 className="text-lg font-black uppercase mb-4">{l.origin} ➔ {l.destination}</h3>
                {!l.isBooked ? (
                  <button onClick={() => handleBook(l._id)} className="w-full bg-black text-white py-3 rounded-xl font-bold hover:bg-red-600 transition">Book Now</button>
                ) : (
                  <button className="w-full bg-gray-300 text-gray-500 py-3 rounded-xl font-bold cursor-not-allowed italic">Sold Out</button>
                )}
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
